	SELECT #{batchJobId} AS batchJobId
		  ,BATCH_JOB_EXECUTION_SEQ.nextVal AS batchExecId
	FROM   DUAL


	SELECT BATCH_JOB_ID AS batchJobId
		  ,BATCH_JOB_EXECUTION_SEQ.nextVal AS batchExecId
	FROM   CMN_BATCH_INFO
	WHERE  EXEC_SERVICE = #{execService}
	AND    USG_YN = 'Y'


/* BatchCommonMapper.insertBatchExecHst */
INSERT INTO CMN_BATCH_EXEC_HST (
	  BATCH_JOB_ID
	, BATCH_EXEC_ID
	, STRT_DTTM
	, STAT_CD
	, EXEC_TYPE_CD
	, EXEC_PARAM
	, BATCH_REQ_ID
	, REG_ID
	, REG_DTTM
	, RVISN_ID
	, RVISN_DTTM
) VALUES (
	  #{batchJobId}
	, #{batchExecId}
	, TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
	, #{statCd}
	, #{execTypeCd}
	, #{execParam}
	, #{batchReqId}
	, #{userId}
	, SYSDATE
	, #{userId}
	, SYSDATE
)

mapper.update:
/* BatchCommonMapper.updateBatchExecHst */
UPDATE CMN_BATCH_EXEC_HST
SET     END_DTTM = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
	   ,STAT_CD = #{statCd}
	   ,EXEC_PARAM = #{execParam}
	   ,EXEC_COUNT = #{execCount}
	   ,ERR_CD = #{errCd}
	   ,ERR_MSG = #{errMsg}
	   ,REMRK = #{remrk}
	   ,RVISN_ID = #{userId}
	   ,RVISN_DTTM = SYSDATE
WHERE  BATCH_JOB_ID = #{batchJobId}
AND    BATCH_EXEC_ID = #{batchExecId}
